   const [prevDataRef, setPrevDataRef] = useState<string>('')
   const dataKey = JSON.stringify({ nodes, edges })
   useEffect(() => {
     if (dataKey === prevDataRef) return
     // ... 执行布局 ...
     setPrevDataRef(dataKey)
   }, [dataKey])

2. 方案B：用 useMemo 缓存 graphology Graph 实例，只在 nodes/edges 内容变化时重建

3. 方案C（最简）：添加 layoutIterations ref 控制刷新频率，如每 3 秒最多刷新一次
